import{_ as a,o as n,c as t,ag as r}from"./chunks/framework.CAXxHpAX.js";const p=JSON.parse('{"title":"Long-Term Engineering Roadmap","description":"","frontmatter":{},"headers":[],"relativePath":"career/long-term-roadmap.md","filePath":"career/long-term-roadmap.md","lastUpdated":null}'),i={name:"career/long-term-roadmap.md"};function o(s,e,l,c,g,d){return n(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="long-term-engineering-roadmap" tabindex="-1">Long-Term Engineering Roadmap <a class="header-anchor" href="#long-term-engineering-roadmap" aria-label="Permalink to &quot;Long-Term Engineering Roadmap&quot;">​</a></h1><p>This note is a compass, not a contract. It exists to keep decisions <strong>consistent over years</strong> as roles, teams, and platforms change.</p><h2 id="becoming-a-stronger-robotics-engineer" tabindex="-1">Becoming a stronger robotics engineer <a class="header-anchor" href="#becoming-a-stronger-robotics-engineer" aria-label="Permalink to &quot;Becoming a stronger robotics engineer&quot;">​</a></h2><p>Depth beats breadth when depth includes <strong>the fundamentals</strong>: kinematics and dynamics, linear systems intuition, probability, and the courage to read papers implementation-first. I want each year to add at least one <strong>durable skill</strong>—for example, better contact modeling, sharper ROS 2 performance instincts, or cleaner evaluation discipline.</p><h2 id="building-technical-assets" tabindex="-1">Building technical assets <a class="header-anchor" href="#building-technical-assets" aria-label="Permalink to &quot;Building technical assets&quot;">​</a></h2><p><strong>Assets</strong> are reusable: open-source tools, high-quality notes, talks, and code templates that make the next project faster. The portfolio pages here are a deliberate archive so lessons do not evaporate when a repository goes read-only.</p><h2 id="writing-consistently" tabindex="-1">Writing consistently <a class="header-anchor" href="#writing-consistently" aria-label="Permalink to &quot;Writing consistently&quot;">​</a></h2><p>Weekly <strong>Tech Logs</strong> keep honesty high and overhead low. Monthly, I promote one or two threads into <strong>Articles</strong> when they clear a simple bar: would I be comfortable revisiting this explanation in public a year later? Writing is part of engineering quality, not a side hobby.</p><h2 id="preparing-for-a-long-engineering-career" tabindex="-1">Preparing for a long engineering career <a class="header-anchor" href="#preparing-for-a-long-engineering-career" aria-label="Permalink to &quot;Preparing for a long engineering career&quot;">​</a></h2><p>Long careers reward <strong>compound learning</strong>: small improvements that stack. That means protecting focus time, learning to say no gracefully, and choosing roles where the feedback loop includes real hardware or realistic proxies—not only slides.</p><h2 id="balancing-depth-health-family-and-financial-stability" tabindex="-1">Balancing depth, health, family, and financial stability <a class="header-anchor" href="#balancing-depth-health-family-and-financial-stability" aria-label="Permalink to &quot;Balancing depth, health, family, and financial stability&quot;">​</a></h2><ul><li><strong>Depth</strong> requires uninterrupted blocks; I treat them as calendar first-class citizens.</li><li><strong>Health</strong> is load-bearing: sleep, strength, and eyesight directly affect debugging quality.</li><li><strong>Family</strong> is non-negotiable presence time; late-night heroics are a planning failure, not a badge.</li><li><strong>Financial stability</strong> reduces fear-driven decisions; boring savings and insurance questions deserve annual attention like a dependency upgrade.</li></ul><h2 id="review-cadence" tabindex="-1">Review cadence <a class="header-anchor" href="#review-cadence" aria-label="Permalink to &quot;Review cadence&quot;">​</a></h2><p>Re-read this roadmap quarterly. Adjust one paragraph at a time rather than rewriting from scratch—small edits track real life better than dramatic manifestos.</p>',14)])])}const m=a(i,[["render",o]]);export{p as __pageData,m as default};
